const context = $input.first().json.context || 'Daily Brief for Ary Ribeiro, consultor IA, 3 verticais TJ TM CL';
const project = $input.first().json.project || '';
const importance = parseInt($input.first().json.importance) || 3;

return [{ json: { context, project, importance } }];

const items = $input.all();

if (!items || items.length === 0 || (items.length === 1 && !items[0].json.summary)) {
  return [{ json: { memoryContext: 'Nenhuma memoria recente encontrada.' } }];
}

const lines = items.map(item => {
  const m = item.json;
  if (!m.summary) return null;
  const date = m.created_at ? m.created_at.substring(0, 10) : 'unknown';
  const sim = m.similarity ? (m.similarity * 100).toFixed(0) + '%' : '';
  return `- [${date}] ${m.type}/${m.project} (imp:${m.importance}, rel:${sim}): ${m.summary}`;
}).filter(Boolean);

if (lines.length === 0) {
  return [{ json: { memoryContext: 'Nenhuma memoria recente encontrada.' } }];
}

const context = `## Memoria Recente (busca semantica)\n${lines.join('\n')}`;

return [{ json: { memoryContext: context } }];
